{
  "files": [
    {
      "path": "package.json",
      "content": "{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple Project Management API using Node.js",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}
"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const app = express();

app.use(express.json());

// Import routes
const projectRoutes = require('./modules/projects/routes');
const taskRoutes = require('./modules/tasks/routes');
const memberRoutes = require('./modules/members/routes');
const commentRoutes = require('./modules/comments/routes');

// Use routes
app.use('/projects', projectRoutes);
app.use('/projects/:projectId/tasks', taskRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentRoutes);
app.use('/projects/:projectId/members', memberRoutes);

// Health check endpoint
app.get('/', (req, res) => {
  res.status(200).json({ message: 'API is running' });
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Something went wrong!' } });
});

module.exports = app;
"
    },
    {
      "path": "src/server.js",
      "content": "const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
"
    }
  ],
  "notes": "Added supertest to dependencies and corrected the app export in src/app.js."
}
